/* ══════════════════════════════════════════════════════════════════════════════
   CELL RENDERER
   ══════════════════════════════════════════════════════════════════════════════ */
function CellValue({ value }) {
  if (value === true) return <span className={s.cellCheck}>{'\u2713'}</span>
  if (value === false) return <span className={s.cellCross}>{'\u2717'}</span>
  const negatives = ['Limited', 'Basic', 'Manual', 'Manual Stops', 'Via Webhooks', 'Community', 'Pine Backtester', 'Standard']
  const isPositive = typeof value === 'string' && !negatives.includes(value)
  return <span className={isPositive ? s.cellPositive : s.cellNeutral}>{value}</span>
}

